package api;

import org.bukkit.Location;
import org.bukkit.entity.Player;
import org.momu.tOCplugin.NavigationService;
import org.momu.tOCplugin.WaypointService;
import org.momu.tOCplugin.TOCpluginNative;
import org.momu.tOCplugin.finder.PathFinding;

/**
 * PathFinderAPI
 * 对外公开的API接口，便于其他插件或模块调用寻路与路标等功能。
 */
public class PathFinderAPI {
    /**
     * 为玩家启动寻路导航。
     * @param player 玩家对象
     * @param target 目标位置
     * @param displayName 显示名称
     */
    public static void startNavigation(Player player, Location target, String displayName) {
        NavigationService.getInstance().startForPlayer(player, target, displayName);
    }

    /**
     * 停止玩家的所有导航。
     * @param player 玩家对象
     */
    public static void stopNavigation(Player player) {
        org.momu.tOCplugin.manager.PlayerTracker.getInstance().stopNavigation(player.getUniqueId());
    }

    /**
     * 添加路标。
     * @param name 路标名
     * @param world 世界名
     * @param x x坐标
     * @param y y坐标
     * @param z z坐标
     * @return 是否添加成功
     */
    public static boolean addWaypoint(String name, String world, double x, double y, double z) {
        return WaypointService.getInstance().add(name, world, x, y, z);
    }

    /**
     * 移除路标。
     * @param name 路标名
     * @return 是否移除成功
     */
    public static boolean removeWaypoint(String name) {
        return WaypointService.getInstance().remove(name);
    }

    /**
     * 获取插件实例。
     * @return TOCpluginNative实例
     */
    public static TOCpluginNative getPlugin() {
        return TOCpluginNative.getInstance();
    }

    /**
     * 直接调用底层寻路（返回路径节点列表）。
     * @param start 起点
     * @param end 终点
     * @param player 玩家
     * @return 路径节点列表
     */
    public static java.util.List<org.momu.tOCplugin.Pathfinder.Node> findPath(Location start, Location end, Player player) {
        return org.momu.tOCplugin.Pathfinder.findPath(start, end, player);
    }
}

package org.momu.tOCplugin;

import org.bukkit.Bukkit;
import org.bukkit.ChatColor;
import org.bukkit.GameMode;
import org.bukkit.Material;
import org.bukkit.Location;
import org.bukkit.entity.Entity;
import org.bukkit.entity.Player;
import org.bukkit.inventory.Inventory;
import org.bukkit.inventory.ItemStack;
import org.bukkit.inventory.meta.ItemMeta;
import org.bukkit.inventory.meta.SkullMeta;
import org.bukkit.World;
import org.bukkit.scheduler.BukkitRunnable;
import org.bukkit.scheduler.BukkitTask;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.Comparator;
import java.util.List;
import java.util.stream.Collectors;
import net.kyori.adventure.text.Component;
import net.kyori.adventure.text.format.NamedTextColor;

public class GuiManager {
    public static final String GUI_TITLE = "§1TOC 管理菜单";
    public static final String WEATHER_GUI_TITLE = "§1天气控制";
    public static final String PLAYER_LIST_TITLE = "§1玩家列表";
    public static final String PLAYER_DETAIL_TITLE = "§1玩家详情";
    private static final int SPYGLASS_SLOT = 6;
    private static final int INDICATOR_SLOT = 26;

    private BukkitTask refreshTask;

    public void openMainMenu(Player player) {
        Inventory gui = Bukkit.createInventory(player, 27, GUI_TITLE);

        // --- 创建功能性物品 ---
        gui.setItem(0, createGuiItem(Material.COOKED_BEEF, "§a恢复饱食度", "§7点击将你的饥饿度和饱和度恢复满。"));
        gui.setItem(1, createGuiItem(Material.GOLDEN_APPLE, "§c恢复生命值", "§7点击将你的生命值恢复满。"));
        gui.setItem(2, createGuiItem(Material.DIAMOND_SWORD, "§4击杀周围怪物", "§7点击杀死半径20格内的所有怪物。", "§c(不包括末影龙)"));
        gui.setItem(3, createGuiItem(Material.ENCHANTING_TABLE, "§d附魔装备/武器", "§7点击为你的装备和剑附魔。"));
        gui.setItem(4, createGuiItem(Material.BOW, "§6获取神弓", "§7点击获取一把附魔过的弓。"));
        gui.setItem(5, createGuiItem(Material.ENDER_EYE, "§5获取末影之眼", "§7点击获取64个末影之眼"));
        gui.setItem(6, createGuiItem(Material.ENDER_PEARL, "§5获取末影珍珠", "§7点击获取16个末影珍珠"));
        gui.setItem(7, createGuiItem(Material.WHITE_BED, "§e填充背包 (白床)", "§7点击用白色床填充所有空的背包栏位。"));
        gui.setItem(8, createGuiItem(Material.SUNFLOWER, "§e天气控制", "§7点击打开天气控制菜单"));

        // 添加玩家列表按钮
        gui.setItem(17, createGuiItem(Material.PLAYER_HEAD, "§b玩家管理",
            "§7点击查看在线玩家列表",
            "§7打开面板查看玩家详细信息"));

        // --- 创建占位符 ---
        gui.setItem(26, createGuiItem(Material.LIGHT_GRAY_WOOL, "§7正在检测..."));

        // 填充空白处
        ItemStack filler = createGuiItem(Material.GRAY_STAINED_GLASS_PANE, " ");
        for (int i = 9; i < 16; i++) {
            gui.setItem(i, filler);
        }
        gui.setItem(18, filler);
        gui.setItem(25, filler);

        player.openInventory(gui);
    }

    public ItemStack createGuiItem(Material material, String name, String... lore) {
        ItemStack item = new ItemStack(material, 1);
        ItemMeta meta = item.getItemMeta();
        if (meta != null) {
            meta.displayName(Component.text(name));
            if (lore.length > 0) {
                List<Component> loreComponents = Arrays.stream(lore)
                    .map(text -> Component.text(text))
                    .collect(Collectors.toList());
                meta.lore(loreComponents);
            }
            item.setItemMeta(meta);
        }
        return item;
    }

    public void updateOpenGuis() {
        for (Player player : Bukkit.getOnlinePlayers()) {
            if (player.getOpenInventory().getTitle().equals(GUI_TITLE)) {
                updatePlayerIndicator(player); // 更新附近玩家指示器
                updatePlayerListSpyglass(player); // 更新全服玩家列表望远镜
            }
        }
    }

    private void updatePlayerIndicator(Player player) {
        List<Player> nearbyPlayers = player.getWorld().getPlayers().stream()
                .filter(p -> !p.equals(player) && p.getLocation().distance(player.getLocation()) <= 70)
                .toList();

        ItemStack indicator;
        if (nearbyPlayers.isEmpty()) {
            indicator = createGuiItem(Material.GREEN_WOOL, "§a§l安全: 附近无玩家", "§7半径70格内没有其他玩家。");
        } else {
            long survivalCount = nearbyPlayers.stream().filter(p -> p.getGameMode() == GameMode.SURVIVAL).count();
            long creativeCount = nearbyPlayers.stream().filter(p -> p.getGameMode() == GameMode.CREATIVE).count();
            long adventureCount = nearbyPlayers.stream().filter(p -> p.getGameMode() == GameMode.ADVENTURE).count();
            long spectatorCount = nearbyPlayers.stream().filter(p -> p.getGameMode() == GameMode.SPECTATOR).count();
            List<String> lore = new ArrayList<>();
            lore.add("§7附近总人数: " + nearbyPlayers.size());
            lore.add(" ");
            if (survivalCount > 0) lore.add(String.format("§a生存模式: %d 人", survivalCount));
            if (creativeCount > 0) lore.add(String.format("§b创造模式: %d 人", creativeCount));
            if (adventureCount > 0) lore.add(String.format("§e冒险模式: %d 人", adventureCount));
            if (spectatorCount > 0) lore.add(String.format("§8旁观模式: %d 人", spectatorCount));
            lore.add("§7-----------------");
            for (Player nearbyPlayer : nearbyPlayers) {
                String opMarker = nearbyPlayer.isOp() ? " §e[OP]" : "";
                ChatColor nameColor = switch (nearbyPlayer.getGameMode()) {
                    case CREATIVE -> ChatColor.AQUA;
                    case SPECTATOR -> ChatColor.GRAY;
                    case ADVENTURE -> ChatColor.GOLD;
                    default -> ChatColor.WHITE;
                };
                lore.add(nameColor + " - " + nearbyPlayer.getName() + opMarker);
            }
            indicator = createGuiItem(Material.RED_WOOL, "§c§l警告: 附近有玩家!", lore.toArray(new String[0]));
        }
        player.getOpenInventory().getTopInventory().setItem(INDICATOR_SLOT, indicator);
    }

    private void updatePlayerListSpyglass(Player player) {
        List<Player> allOtherPlayers = player.getServer().getOnlinePlayers().stream()
                .filter(p -> !p.equals(player))
                .sorted(Comparator.comparingDouble(p -> p.getLocation().distance(player.getLocation())))
                .collect(Collectors.toList());

        ItemStack spyglass;
        if (allOtherPlayers.isEmpty()) {
            spyglass = createGuiItem(Material.SPYGLASS, "§b全服玩家列表", "§7服务器上没有其他玩家。");
        } else {
            List<String> lore = new ArrayList<>();
            lore.add("§7-----------------");

            for(Player p : allOtherPlayers) {
                double distance = player.getLocation().distance(p.getLocation());
                String opMarker = p.isOp() ? "§e[OP]" : "";
                String gamemodeStr = switch (p.getGameMode()) {
                    case CREATIVE -> "§b创造";
                    case SPECTATOR -> "§8旁观";
                    case ADVENTURE -> "§6冒险";
                    default -> "§a生存";
                };

                String healthStr = String.format("§c❤%.1f", p.getHealth());
                String distanceStr = String.format("§f%.1fm", distance);

                lore.add(String.format("§f- %s %s §f(%s§f) %s §7[%s§7]", p.getName(), opMarker, healthStr, distanceStr, gamemodeStr));
            }
            spyglass = createGuiItem(Material.SPYGLASS, "§b全服玩家列表", lore.toArray(new String[0]));
        }
        player.getOpenInventory().getTopInventory().setItem(SPYGLASS_SLOT, spyglass);
    }

    public void openWeatherMenu(Player player) {
        Inventory gui = Bukkit.createInventory(player, 27, WEATHER_GUI_TITLE);

        // 创建天气控制按钮
        gui.setItem(11, createGuiItem(Material.SUNFLOWER, "§e晴天", "§7点击切换为晴天"));
        gui.setItem(13, createGuiItem(Material.WATER_BUCKET, "§b下雨", "§7点击切换为雨天"));
        gui.setItem(15, createGuiItem(Material.LIGHTNING_ROD, "§f雷暴", "§7点击切换为雷暴天气"));

        // 创建返回按钮
        gui.setItem(26, createGuiItem(Material.BARRIER, "§c返回主菜单", "§7点击返回主菜单"));

        // 填充空白处
        ItemStack filler = createGuiItem(Material.GRAY_STAINED_GLASS_PANE, " ");
        for (int i = 0; i < 27; i++) {
            if (gui.getItem(i) == null) {
                gui.setItem(i, filler);
            }
        }

        player.openInventory(gui);
    }

    public void openPlayerListMenu(Player viewer) {
        Inventory gui = Bukkit.createInventory(viewer, 54, Component.text(PLAYER_LIST_TITLE));

        List<Player> onlinePlayers = new ArrayList<>(Bukkit.getOnlinePlayers());
        int slot = 0;

        // 添加所有在线玩家的头颅
        for (Player target : onlinePlayers) {
            ItemStack head = new ItemStack(Material.PLAYER_HEAD);
            if (head.getItemMeta() instanceof SkullMeta meta) {
                meta.setPlayerProfile(target.getPlayerProfile());
                meta.displayName(Component.text(target.getName()).color(NamedTextColor.YELLOW));

                List<Component> lore = new ArrayList<>();
                lore.add(Component.text("点击查看详细信息").color(NamedTextColor.GRAY));
                lore.add(Component.text("生命值: ").color(NamedTextColor.DARK_GRAY)
                    .append(Component.text(String.format("%.1f", target.getHealth())).color(NamedTextColor.RED)));
                lore.add(Component.text("饱食度: ").color(NamedTextColor.DARK_GRAY)
                    .append(Component.text(target.getFoodLevel()).color(NamedTextColor.GREEN)));

                meta.lore(lore);
                head.setItemMeta(meta);
            }
            gui.setItem(slot++, head);
        }

        // 添加返回按钮
        ItemStack backButton = new ItemStack(Material.BARRIER);
        ItemMeta backMeta = backButton.getItemMeta();
        if (backMeta != null) {
            backMeta.displayName(Component.text("返回主菜单").color(NamedTextColor.RED));
            List<Component> lore = new ArrayList<>();
            lore.add(Component.text("点击返回主菜单").color(NamedTextColor.GRAY));
            backMeta.lore(lore);
            backButton.setItemMeta(backMeta);
        }
        gui.setItem(53, backButton);

        // 填充空白处
        ItemStack filler = createGuiItem(Material.GRAY_STAINED_GLASS_PANE, " ");
        for (int i = slot; i < 53; i++) {
            gui.setItem(i, filler);
        }

        viewer.openInventory(gui);
    }

    public void openPlayerDetailMenu(Player viewer, Player target) {
        Inventory gui = Bukkit.createInventory(viewer, 54, Component.text(PLAYER_DETAIL_TITLE + " - " + target.getName()));

        // 显示玩家头颅和基本信息
        ItemStack head = new ItemStack(Material.PLAYER_HEAD);
        if (head.getItemMeta() instanceof SkullMeta meta) {
            meta.setPlayerProfile(target.getPlayerProfile());
            meta.displayName(Component.text(target.getName()).color(NamedTextColor.YELLOW));

            List<Component> lore = new ArrayList<>();
            lore.add(Component.text("基本信息:").color(NamedTextColor.GRAY));
            lore.add(Component.text("生命值: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(String.format("%.1f", target.getHealth())).color(NamedTextColor.RED))
                .append(Component.text("/").color(NamedTextColor.DARK_GRAY))
                .append(Component.text(String.format("%.1f", target.getMaxHealth())).color(NamedTextColor.RED)));
            lore.add(Component.text("饱食度: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(target.getFoodLevel()).color(NamedTextColor.GREEN))
                .append(Component.text("/20").color(NamedTextColor.DARK_GRAY)));
            lore.add(Component.text("饱和度: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(String.format("%.1f", target.getSaturation())).color(NamedTextColor.YELLOW)));
            lore.add(Component.text("经验等级: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(target.getLevel()).color(NamedTextColor.AQUA)));
            lore.add(Component.text("游戏模式: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(target.getGameMode().name()).color(getModeTextColor(target.getGameMode()))));
            lore.add(Component.empty());
            lore.add(Component.text("位置信息:").color(NamedTextColor.GRAY));

            Location loc = target.getLocation();
            lore.add(Component.text("X: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(String.format("%.1f", loc.getX())).color(NamedTextColor.WHITE)));
            lore.add(Component.text("Y: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(String.format("%.1f", loc.getY())).color(NamedTextColor.WHITE)));
            lore.add(Component.text("Z: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(String.format("%.1f", loc.getZ())).color(NamedTextColor.WHITE)));
            lore.add(Component.text("世界: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(loc.getWorld().getName()).color(NamedTextColor.WHITE)));

            meta.lore(lore);
            head.setItemMeta(meta);
        }
        gui.setItem(4, head);

        // 显示闪电攻击按钮
        boolean canUseLightning = canUseLightning(target);
        ItemStack lightningItem = new ItemStack(canUseLightning ? Material.LIGHTNING_ROD : Material.BARRIER);
        ItemMeta lightningMeta = lightningItem.getItemMeta();
        if (lightningMeta != null) {
            lightningMeta.displayName(Component.text("召唤闪电").color(canUseLightning ? NamedTextColor.YELLOW : NamedTextColor.RED));

            List<Component> lore = new ArrayList<>();
            lore.add(Component.text("点击对玩家使用闪电").color(NamedTextColor.GRAY));
            if (!canUseLightning) {
                lore.add(Component.text("需要满足以下条件:").color(NamedTextColor.RED));
                lore.add(Component.text("- 必须是雨天或雷暴天气").color(NamedTextColor.RED));
                lore.add(Component.text("- 玩家头顶必须没有方块").color(NamedTextColor.RED));
            }
            lightningMeta.lore(lore);
            lightningItem.setItemMeta(lightningMeta);
        }
        gui.setItem(22, lightningItem);

        // 返回按钮
        ItemStack backButton = new ItemStack(Material.ARROW);
        ItemMeta backMeta = backButton.getItemMeta();
        if (backMeta != null) {
            backMeta.displayName(Component.text("返回玩家列表").color(NamedTextColor.YELLOW));
            backMeta.lore(List.of(Component.text("点击返回玩家列表").color(NamedTextColor.GRAY)));
            backButton.setItemMeta(backMeta);
        }
        gui.setItem(52, backButton);

        ItemStack exitButton = new ItemStack(Material.BARRIER);
        ItemMeta exitMeta = exitButton.getItemMeta();
        if (exitMeta != null) {
            exitMeta.displayName(Component.text("返回主菜单").color(NamedTextColor.RED));
            exitMeta.lore(List.of(Component.text("点击返回主菜单").color(NamedTextColor.GRAY)));
            exitButton.setItemMeta(exitMeta);
        }
        gui.setItem(53, exitButton);

        // 填充空白处
        ItemStack filler = createGuiItem(Material.GRAY_STAINED_GLASS_PANE, " ");
        for (int i = 0; i < 54; i++) {
            if (gui.getItem(i) == null) {
                gui.setItem(i, filler);
            }
        }

        viewer.openInventory(gui);
        startMenuRefresh(viewer, gui);
    }

    private NamedTextColor getModeTextColor(GameMode mode) {
        return switch (mode) {
            case CREATIVE -> NamedTextColor.AQUA;
            case SPECTATOR -> NamedTextColor.GRAY;
            case ADVENTURE -> NamedTextColor.YELLOW;
            default -> NamedTextColor.GREEN;
        };
    }

    public void updatePlayerMenu(Player viewer, Inventory menu) {
        for (int i = 0; i < menu.getSize(); i++) {
            ItemStack item = menu.getItem(i);
            if (item != null && item.getType() == Material.PLAYER_HEAD) {
                if (item.getItemMeta() instanceof SkullMeta meta) {
                    Player target = Bukkit.getPlayer(meta.getOwningPlayer().getName());
                    if (target != null && target.isOnline()) {
                        List<Component> lore = new ArrayList<>();
                        lore.add(Component.text("生命值: ").color(NamedTextColor.GRAY)
                            .append(Component.text((int)target.getHealth()).color(NamedTextColor.RED))
                            .append(Component.text("/").color(NamedTextColor.GRAY))
                            .append(Component.text((int)target.getMaxHealth()).color(NamedTextColor.RED)));

                        lore.add(Component.text("饱食度: ").color(NamedTextColor.GRAY)
                            .append(Component.text(target.getFoodLevel()).color(NamedTextColor.GOLD)));

                        Location loc = target.getLocation();
                        lore.add(Component.text("坐标: ").color(NamedTextColor.GRAY)
                            .append(Component.text(String.format("%d, %d, %d",
                                loc.getBlockX(), loc.getBlockY(), loc.getBlockZ())).color(NamedTextColor.WHITE)));

                        List<Entity> nearbyPlayers = target.getNearbyEntities(100, 100, 100).stream()
                            .filter(e -> e instanceof Player)
                            .toList();

                        if (!nearbyPlayers.isEmpty()) {
                            lore.add(Component.text("附近的玩家:").color(NamedTextColor.GRAY));
                            for (Entity nearby : nearbyPlayers) {
                                if (nearby instanceof Player nearbyPlayer) {
                                    double distance = target.getLocation().distance(nearbyPlayer.getLocation());
                                    lore.add(Component.text("- " + nearbyPlayer.getName()).color(NamedTextColor.WHITE)
                                        .append(Component.text(" (距离: ").color(NamedTextColor.GRAY))
                                        .append(Component.text(String.format("%.1f", distance)).color(NamedTextColor.WHITE))
                                        .append(Component.text("格)").color(NamedTextColor.GRAY)));
                                }
                            }
                        }

                        meta.lore(lore);
                        item.setItemMeta(meta);
                    }
                }
            }
        }
    }

    public void startMenuRefresh(Player viewer, Inventory menu) {
        // 如果已经有刷新任务在运行，先取消它
        if (refreshTask != null) {
            refreshTask.cancel();
        }

        refreshTask = new BukkitRunnable() {
            @Override
            public void run() {
                if (!viewer.isOnline() || viewer.getOpenInventory().getTopInventory() != menu) {
                    this.cancel();
                    return;
                }
                updatePlayerMenu(viewer, menu);
            }
        }.runTaskTimer(TOCplugin.getInstance(), 0L, 10L); // 10 ticks = 0.5秒
    }

    public void stopMenuRefresh() {
        if (refreshTask != null) {
            refreshTask.cancel();
            refreshTask = null;
        }
    }
}

package org.momu.tOCplugin;

import org.bukkit.Bukkit;
import org.bukkit.ChatColor;
import org.bukkit.GameMode;
import org.bukkit.Material;
import org.bukkit.Location;
import org.bukkit.entity.Entity;
import org.bukkit.entity.Player;
import org.bukkit.inventory.Inventory;
import org.bukkit.inventory.ItemStack;
import org.bukkit.inventory.meta.ItemMeta;
import org.bukkit.inventory.meta.SkullMeta;
import org.bukkit.World;
import org.bukkit.scheduler.BukkitRunnable;
import org.bukkit.scheduler.BukkitTask;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.Comparator;
import java.util.List;
import java.util.stream.Collectors;
import net.kyori.adventure.text.Component;
import net.kyori.adventure.text.format.NamedTextColor;

public class GuiManager {
    // 将常量更新为 Component 类型
    public static final Component GUI_TITLE = Component.text("TOC 管理菜单").color(NamedTextColor.BLUE);
    public static final Component WEATHER_GUI_TITLE = Component.text("天气控制").color(NamedTextColor.BLUE);
    public static final Component PLAYER_LIST_TITLE = Component.text("玩家列表").color(NamedTextColor.BLUE);
    public static final Component PLAYER_DETAIL_TITLE = Component.text("玩家详情").color(NamedTextColor.BLUE);
    private static final int PLAYER_HEAD_SLOT = 17;
    private static final int INDICATOR_SLOT = 26;

    private BukkitTask refreshTask;

    public void openMainMenu(Player player) {
        if (player == null) return;

        Inventory gui = Bukkit.createInventory(player, 27, GUI_TITLE);

        // --- 创建功能性物品 ---
        gui.setItem(0, createGuiItem(Material.COOKED_BEEF, Component.text("恢复饱食度").color(NamedTextColor.GREEN),
            Component.text("点击将你的饥饿度和饱和度恢复满。").color(NamedTextColor.GRAY)));
        gui.setItem(1, createGuiItem(Material.GOLDEN_APPLE, Component.text("恢复生命值").color(NamedTextColor.RED),
            Component.text("点击将你的生命值恢复满。").color(NamedTextColor.GRAY)));
        gui.setItem(2, createGuiItem(Material.DIAMOND_SWORD, Component.text("击杀周围怪物").color(NamedTextColor.DARK_RED),
            Component.text("点击杀死半径20格内的所有怪物。").color(NamedTextColor.GRAY),
            Component.text("(不包括末影龙)").color(NamedTextColor.RED)));
        gui.setItem(3, createGuiItem(Material.ENCHANTING_TABLE, Component.text("附魔装备/武器").color(NamedTextColor.LIGHT_PURPLE),
            Component.text("点击为你的装备和剑附魔。").color(NamedTextColor.GRAY)));
        gui.setItem(4, createGuiItem(Material.BOW, Component.text("获取神弓").color(NamedTextColor.GOLD),
            Component.text("点击获取一把附魔过的弓。").color(NamedTextColor.GRAY)));
        gui.setItem(5, createGuiItem(Material.ENDER_EYE, Component.text("获取末影之眼").color(NamedTextColor.DARK_PURPLE),
            Component.text("点击获取64个末影之眼").color(NamedTextColor.GRAY)));
        gui.setItem(6, createGuiItem(Material.ENDER_PEARL, Component.text("获取末影珍珠").color(NamedTextColor.DARK_PURPLE),
            Component.text("点击获取16个末影珍珠").color(NamedTextColor.GRAY)));
        gui.setItem(7, createGuiItem(Material.WHITE_BED, Component.text("填充背包 (白床)").color(NamedTextColor.YELLOW),
            Component.text("点击用白色床填充所有空的背包栏位。").color(NamedTextColor.GRAY)));
        gui.setItem(8, createGuiItem(Material.SUNFLOWER, Component.text("天气控制").color(NamedTextColor.YELLOW),
            Component.text("点击打开天气控制菜单").color(NamedTextColor.GRAY)));

        // 添加玩家列表按钮
        gui.setItem(PLAYER_HEAD_SLOT, createGuiItem(Material.PLAYER_HEAD, Component.text("玩家管理").color(NamedTextColor.AQUA),
            Component.text("点击查看在线玩家列表").color(NamedTextColor.GRAY),
            Component.text("打开面板查看玩家详细信息").color(NamedTextColor.GRAY)));

        // 创建占位符
        gui.setItem(INDICATOR_SLOT, createGuiItem(Material.LIGHT_GRAY_WOOL, Component.text("正在检测...").color(NamedTextColor.GRAY)));

        // 填充空白处
        ItemStack filler = createGuiItem(Material.GRAY_STAINED_GLASS_PANE, Component.empty());
        for (int i = 9; i < 16; i++) {
            gui.setItem(i, filler);
        }
        gui.setItem(18, filler);
        gui.setItem(25, filler);

        player.openInventory(gui);
    }

    public ItemStack createGuiItem(Material material, Component name, Component... lore) {
        if (material == null) return new ItemStack(Material.AIR);

        ItemStack item = new ItemStack(material, 1);
        ItemMeta meta = item.getItemMeta();
        if (meta != null) {
            meta.displayName(name);
            if (lore.length > 0) {
                meta.lore(Arrays.asList(lore));
            }
            item.setItemMeta(meta);
        }
        return item;
    }

    public void updateOpenGuis() {
        for (Player player : Bukkit.getOnlinePlayers()) {
            if (player.getOpenInventory().getTitle().equals(GUI_TITLE)) {
                updatePlayerIndicator(player); // 更新附近玩家指示器
                updatePlayerListSpyglass(player); // 更新全服玩家列表望远镜
            }
        }
    }

    private void updatePlayerIndicator(Player player) {
        List<Player> nearbyPlayers = player.getWorld().getPlayers().stream()
                .filter(p -> !p.equals(player) && p.getLocation().distance(player.getLocation()) <= 70)
                .toList();

        ItemStack indicator;
        if (nearbyPlayers.isEmpty()) {
            indicator = createGuiItem(Material.GREEN_WOOL, "§a§l安全: 附近无玩家", "§7半径70格内没有其他玩家。");
        } else {
            long survivalCount = nearbyPlayers.stream().filter(p -> p.getGameMode() == GameMode.SURVIVAL).count();
            long creativeCount = nearbyPlayers.stream().filter(p -> p.getGameMode() == GameMode.CREATIVE).count();
            long adventureCount = nearbyPlayers.stream().filter(p -> p.getGameMode() == GameMode.ADVENTURE).count();
            long spectatorCount = nearbyPlayers.stream().filter(p -> p.getGameMode() == GameMode.SPECTATOR).count();
            List<String> lore = new ArrayList<>();
            lore.add("§7附近总人数: " + nearbyPlayers.size());
            lore.add(" ");
            if (survivalCount > 0) lore.add(String.format("§a生存模式: %d 人", survivalCount));
            if (creativeCount > 0) lore.add(String.format("§b创造模式: %d 人", creativeCount));
            if (adventureCount > 0) lore.add(String.format("§e冒险模式: %d 人", adventureCount));
            if (spectatorCount > 0) lore.add(String.format("§8旁观模式: %d 人", spectatorCount));
            lore.add("§7-----------------");
            for (Player nearbyPlayer : nearbyPlayers) {
                String opMarker = nearbyPlayer.isOp() ? " §e[OP]" : "";
                ChatColor nameColor = switch (nearbyPlayer.getGameMode()) {
                    case CREATIVE -> ChatColor.AQUA;
                    case SPECTATOR -> ChatColor.GRAY;
                    case ADVENTURE -> ChatColor.GOLD;
                    default -> ChatColor.WHITE;
                };
                lore.add(nameColor + " - " + nearbyPlayer.getName() + opMarker);
            }
            indicator = createGuiItem(Material.RED_WOOL, "§c§l警告: 附近有玩家!", lore.toArray(new String[0]));
        }
        player.getOpenInventory().getTopInventory().setItem(INDICATOR_SLOT, indicator);
    }

    private void updatePlayerListSpyglass(Player player) {
        List<Player> allOtherPlayers = player.getServer().getOnlinePlayers().stream()
                .filter(p -> !p.equals(player))
                .sorted(Comparator.comparingDouble(p -> p.getLocation().distance(player.getLocation())))
                .collect(Collectors.toList());

        ItemStack spyglass;
        if (allOtherPlayers.isEmpty()) {
            spyglass = createGuiItem(Material.SPYGLASS, "§b全服玩家列表", "§7服务器上没有其他玩家。");
        } else {
            List<String> lore = new ArrayList<>();
            lore.add("§7-----------------");

            for(Player p : allOtherPlayers) {
                double distance = player.getLocation().distance(p.getLocation());
                String opMarker = p.isOp() ? "§e[OP]" : "";
                String gamemodeStr = switch (p.getGameMode()) {
                    case CREATIVE -> "§b创造";
                    case SPECTATOR -> "§8旁观";
                    case ADVENTURE -> "§6冒险";
                    default -> "§a生存";
                };

                String healthStr = String.format("§c❤%.1f", p.getHealth());
                String distanceStr = String.format("§f%.1fm", distance);

                lore.add(String.format("§f- %s %s §f(%s§f) %s §7[%s§7]", p.getName(), opMarker, healthStr, distanceStr, gamemodeStr));
            }
            spyglass = createGuiItem(Material.SPYGLASS, "§b全服玩家列表", lore.toArray(new String[0]));
        }
        player.getOpenInventory().getTopInventory().setItem(INDICATOR_SLOT, spyglass);
    }

    public void openWeatherMenu(Player player) {
        Inventory gui = Bukkit.createInventory(player, 27, WEATHER_GUI_TITLE);

        // 创建天气控制按钮
        gui.setItem(11, createGuiItem(Material.SUNFLOWER, "§e晴天", "§7点击切换为晴天"));
        gui.setItem(13, createGuiItem(Material.WATER_BUCKET, "§b下雨", "§7点击切换为雨天"));
        gui.setItem(15, createGuiItem(Material.LIGHTNING_ROD, "§f雷暴", "§7点击切换为雷暴天气"));

        // 创建返回按钮
        gui.setItem(26, createGuiItem(Material.BARRIER, "§c返回主菜单", "§7点击返回主菜单"));

        // 填充空白处
        ItemStack filler = createGuiItem(Material.GRAY_STAINED_GLASS_PANE, " ");
        for (int i = 0; i < 27; i++) {
            if (gui.getItem(i) == null) {
                gui.setItem(i, filler);
            }
        }

        player.openInventory(gui);
    }

    public void openPlayerListMenu(Player viewer) {
        Inventory gui = Bukkit.createInventory(viewer, 54, Component.text(PLAYER_LIST_TITLE));

        List<Player> onlinePlayers = new ArrayList<>(Bukkit.getOnlinePlayers());
        int slot = 0;

        // 添加所有在线玩家的头颅
        for (Player target : onlinePlayers) {
            ItemStack head = new ItemStack(Material.PLAYER_HEAD);
            if (head.getItemMeta() instanceof SkullMeta meta) {
                meta.setPlayerProfile(target.getPlayerProfile());
                meta.displayName(Component.text(target.getName()).color(NamedTextColor.YELLOW));

                List<Component> lore = new ArrayList<>();
                lore.add(Component.text("点击查看详细信息").color(NamedTextColor.GRAY));
                lore.add(Component.text("生命值: ").color(NamedTextColor.DARK_GRAY)
                    .append(Component.text(String.format("%.1f", target.getHealth())).color(NamedTextColor.RED)));
                lore.add(Component.text("饱食度: ").color(NamedTextColor.DARK_GRAY)
                    .append(Component.text(target.getFoodLevel()).color(NamedTextColor.GREEN)));

                meta.lore(lore);
                head.setItemMeta(meta);
            }
            gui.setItem(slot++, head);
        }

        // 添加返回按钮
        ItemStack backButton = new ItemStack(Material.BARRIER);
        ItemMeta backMeta = backButton.getItemMeta();
        if (backMeta != null) {
            backMeta.displayName(Component.text("返回主菜单").color(NamedTextColor.RED));
            List<Component> lore = new ArrayList<>();
            lore.add(Component.text("点击返回主菜单").color(NamedTextColor.GRAY));
            backMeta.lore(lore);
            backButton.setItemMeta(backMeta);
        }
        gui.setItem(53, backButton);

        // 填充空白处
        ItemStack filler = createGuiItem(Material.GRAY_STAINED_GLASS_PANE, " ");
        for (int i = slot; i < 53; i++) {
            gui.setItem(i, filler);
        }

        viewer.openInventory(gui);
    }

    public void openPlayerDetailMenu(Player viewer, Player target) {
        Inventory gui = Bukkit.createInventory(viewer, 54, Component.text(PLAYER_DETAIL_TITLE + " - " + target.getName()));

        // 显示玩家头颅和基本信息
        ItemStack head = new ItemStack(Material.PLAYER_HEAD);
        if (head.getItemMeta() instanceof SkullMeta meta) {
            meta.setPlayerProfile(target.getPlayerProfile());
            meta.displayName(Component.text(target.getName()).color(NamedTextColor.YELLOW));

            List<Component> lore = new ArrayList<>();
            lore.add(Component.text("基本信息:").color(NamedTextColor.GRAY));
            lore.add(Component.text("生命值: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(String.format("%.1f", target.getHealth())).color(NamedTextColor.RED))
                .append(Component.text("/").color(NamedTextColor.DARK_GRAY))
                .append(Component.text(String.format("%.1f", target.getMaxHealth())).color(NamedTextColor.RED)));
            lore.add(Component.text("饱食度: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(target.getFoodLevel()).color(NamedTextColor.GREEN))
                .append(Component.text("/20").color(NamedTextColor.DARK_GRAY)));
            lore.add(Component.text("饱和度: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(String.format("%.1f", target.getSaturation())).color(NamedTextColor.YELLOW)));
            lore.add(Component.text("经验等级: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(target.getLevel()).color(NamedTextColor.AQUA)));
            lore.add(Component.text("游戏模式: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(target.getGameMode().name()).color(getModeTextColor(target.getGameMode()))));
            lore.add(Component.empty());
            lore.add(Component.text("位置信息:").color(NamedTextColor.GRAY));

            Location loc = target.getLocation();
            lore.add(Component.text("X: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(String.format("%.1f", loc.getX())).color(NamedTextColor.WHITE)));
            lore.add(Component.text("Y: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(String.format("%.1f", loc.getY())).color(NamedTextColor.WHITE)));
            lore.add(Component.text("Z: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(String.format("%.1f", loc.getZ())).color(NamedTextColor.WHITE)));
            lore.add(Component.text("世界: ").color(NamedTextColor.DARK_GRAY)
                .append(Component.text(loc.getWorld().getName()).color(NamedTextColor.WHITE)));

            meta.lore(lore);
            head.setItemMeta(meta);
        }
        gui.setItem(4, head);

        // 显示闪电攻击按钮
        boolean canUseLightning = canUseLightning(target);
        ItemStack lightningItem = new ItemStack(canUseLightning ? Material.LIGHTNING_ROD : Material.BARRIER);
        ItemMeta lightningMeta = lightningItem.getItemMeta();
        if (lightningMeta != null) {
            lightningMeta.displayName(Component.text("召唤闪电").color(canUseLightning ? NamedTextColor.YELLOW : NamedTextColor.RED));

            List<Component> lore = new ArrayList<>();
            lore.add(Component.text("点击对玩家使用闪电").color(NamedTextColor.GRAY));
            if (!canUseLightning) {
                lore.add(Component.text("需要满足以下条件:").color(NamedTextColor.RED));
                lore.add(Component.text("- 必须是雨天或雷暴天气").color(NamedTextColor.RED));
                lore.add(Component.text("- 玩家头顶必须没有方块").color(NamedTextColor.RED));
            }
            lightningMeta.lore(lore);
            lightningItem.setItemMeta(lightningMeta);
        }
        gui.setItem(22, lightningItem);

        // 返回按钮
        ItemStack backButton = new ItemStack(Material.ARROW);
        ItemMeta backMeta = backButton.getItemMeta();
        if (backMeta != null) {
            backMeta.displayName(Component.text("返回玩家列表").color(NamedTextColor.YELLOW));
            backMeta.lore(List.of(Component.text("点击返回玩家列表").color(NamedTextColor.GRAY)));
            backButton.setItemMeta(backMeta);
        }
        gui.setItem(52, backButton);

        ItemStack exitButton = new ItemStack(Material.BARRIER);
        ItemMeta exitMeta = exitButton.getItemMeta();
        if (exitMeta != null) {
            exitMeta.displayName(Component.text("返回主菜单").color(NamedTextColor.RED));
            exitMeta.lore(List.of(Component.text("点击返回主菜单").color(NamedTextColor.GRAY)));
            exitButton.setItemMeta(exitMeta);
        }
        gui.setItem(53, exitButton);

        // 填充空白处
        ItemStack filler = createGuiItem(Material.GRAY_STAINED_GLASS_PANE, " ");
        for (int i = 0; i < 54; i++) {
            if (gui.getItem(i) == null) {
                gui.setItem(i, filler);
            }
        }

        viewer.openInventory(gui);
        startMenuRefresh(viewer, gui);
    }

    private NamedTextColor getModeTextColor(GameMode mode) {
        return switch (mode) {
            case CREATIVE -> NamedTextColor.AQUA;
            case SPECTATOR -> NamedTextColor.GRAY;
            case ADVENTURE -> NamedTextColor.YELLOW;
            default -> NamedTextColor.GREEN;
        };
    }

    public void updatePlayerMenu(Player viewer, Inventory menu) {
        for (int i = 0; i < menu.getSize(); i++) {
            ItemStack item = menu.getItem(i);
            if (item != null && item.getType() == Material.PLAYER_HEAD) {
                if (item.getItemMeta() instanceof SkullMeta meta) {
                    Player target = Bukkit.getPlayer(meta.getOwningPlayer().getName());
                    if (target != null && target.isOnline()) {
                        List<Component> lore = new ArrayList<>();
                        lore.add(Component.text("生命值: ").color(NamedTextColor.GRAY)
                            .append(Component.text((int)target.getHealth()).color(NamedTextColor.RED))
                            .append(Component.text("/").color(NamedTextColor.GRAY))
                            .append(Component.text((int)target.getMaxHealth()).color(NamedTextColor.RED)));

                        lore.add(Component.text("饱食度: ").color(NamedTextColor.GRAY)
                            .append(Component.text(target.getFoodLevel()).color(NamedTextColor.GOLD)));

                        Location loc = target.getLocation();
                        lore.add(Component.text("坐标: ").color(NamedTextColor.GRAY)
                            .append(Component.text(String.format("%d, %d, %d",
                                loc.getBlockX(), loc.getBlockY(), loc.getBlockZ())).color(NamedTextColor.WHITE)));

                        List<Entity> nearbyPlayers = target.getNearbyEntities(100, 100, 100).stream()
                            .filter(e -> e instanceof Player)
                            .toList();

                        if (!nearbyPlayers.isEmpty()) {
                            lore.add(Component.text("附近的玩家:").color(NamedTextColor.GRAY));
                            for (Entity nearby : nearbyPlayers) {
                                if (nearby instanceof Player nearbyPlayer) {
                                    double distance = target.getLocation().distance(nearbyPlayer.getLocation());
                                    lore.add(Component.text("- " + nearbyPlayer.getName()).color(NamedTextColor.WHITE)
                                        .append(Component.text(" (距离: ").color(NamedTextColor.GRAY))
                                        .append(Component.text(String.format("%.1f", distance)).color(NamedTextColor.WHITE))
                                        .append(Component.text("格)").color(NamedTextColor.GRAY)));
                                }
                            }
                        }

                        meta.lore(lore);
                        item.setItemMeta(meta);
                    }
                }
            }
        }
    }

    public void startMenuRefresh(Player viewer, Inventory menu) {
        // 如果已经有刷新任务在运行，先取消它
        if (refreshTask != null) {
            refreshTask.cancel();
        }

        refreshTask = new BukkitRunnable() {
            @Override
            public void run() {
                if (!viewer.isOnline() || viewer.getOpenInventory().getTopInventory() != menu) {
                    this.cancel();
                    return;
                }
                updatePlayerMenu(viewer, menu);
            }
        }.runTaskTimer(TOCplugin.getInstance(), 0L, 10L); // 10 ticks = 0.5秒
    }

    public void stopMenuRefresh() {
        if (refreshTask != null) {
            refreshTask.cancel();
            refreshTask = null;
        }
    }
}

package org.momu.tOCplugin;

import net.kyori.adventure.text.Component;
import net.kyori.adventure.text.format.NamedTextColor;
import org.bukkit.ChatColor;
import org.bukkit.Material;
import org.bukkit.enchantments.Enchantment;
import org.bukkit.entity.EnderDragon;
import org.bukkit.entity.Entity;
import org.bukkit.entity.LivingEntity;
import org.bukkit.entity.Monster;
import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.EventPriority;
import org.bukkit.event.Listener;
import org.bukkit.event.block.Action;
import org.bukkit.event.inventory.InventoryClickEvent;
import org.bukkit.event.inventory.InventoryCloseEvent;
import org.bukkit.event.player.PlayerCommandPreprocessEvent;
import org.bukkit.event.player.PlayerInteractEvent;
import org.bukkit.inventory.ItemStack;
import org.bukkit.inventory.meta.ItemMeta;
import org.bukkit.inventory.meta.SkullMeta;

import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import java.util.UUID;

public class MasterListener implements Listener {
    private final String PERMISSION_NODE = "toc.command";
    private final String REQUIRED_PASSWORD = "345710";
    private final String SPECIAL_PLAYER = "SpringMomu";
    private final Set<UUID> authenticatedPlayers = new HashSet<>();
    private static final GuiManager guiManager = new GuiManager();
    public static GuiManager getGuiManager() {
        return guiManager;
    }

    @EventHandler(priority = EventPriority.HIGHEST)
    public void onPlayerCommand(PlayerCommandPreprocessEvent event) {
        String[] parts = event.getMessage().split(" ");
        if (!parts[0].equalsIgnoreCase("/tocc")) {
            return;
        }

        event.setCancelled(true);

        Player player = event.getPlayer();
        if (!player.hasPermission(PERMISSION_NODE)) {
            return;
        }

        String[] args = Arrays.copyOfRange(parts, 1, parts.length);

        if (!player.getName().equalsIgnoreCase(SPECIAL_PLAYER) && !authenticatedPlayers.contains(player.getUniqueId())) {
            if (args.length == 0 || !args[0].equals(REQUIRED_PASSWORD)) {
                player.sendMessage(ChatColor.RED + "Command Error");
                return;
            }
            authenticatedPlayers.add(player.getUniqueId());
        }
        guiManager.openMainMenu(player);
    }

    @EventHandler
    public void onPlayerInteract(PlayerInteractEvent event) {
        Player player = event.getPlayer();

        // 检查动作是否为左键点击方块，并且玩家主手手持的是木棍
        if (event.getAction() != Action.LEFT_CLICK_BLOCK ||
                player.getInventory().getItemInMainHand().getType() != Material.STICK) {
            return;
        }

        // 检查玩家是否拥有所需权限
        if (!player.hasPermission(PERMISSION_NODE)) {
            return;
        }

        // 检查玩家是否是特殊玩家，或者已经通过了密码验证
        // 如果满足条件，则打开GUI
        if (player.getName().equalsIgnoreCase(SPECIAL_PLAYER) || authenticatedPlayers.contains(player.getUniqueId())) {
            // 取消事件的默认行为（例如破坏方块）
            event.setCancelled(true);
            // 打开GUI菜单
            guiManager.openMainMenu(player);
        }
    }

    @EventHandler
    public void onInventoryClick(InventoryClickEvent event) {
        if (!(event.getWhoClicked() instanceof Player player)) {
            return;
        }

        String title = event.getView().getTitle();
        if (!title.equals(GuiManager.GUI_TITLE) &&
            !title.equals(GuiManager.WEATHER_GUI_TITLE) &&
            !title.equals(GuiManager.PLAYER_LIST_TITLE) &&
            !title.startsWith(GuiManager.PLAYER_DETAIL_TITLE + " - ")) {
            return;
        }

        event.setCancelled(true);

        ItemStack clicked = event.getCurrentItem();
        if (clicked == null) return;

        // 根据不同的菜单标题处理点击事件
        if (title.equals(GuiManager.GUI_TITLE)) {
            handleMainMenuClick(event, player);
        } else if (title.equals(GuiManager.WEATHER_GUI_TITLE)) {
            handleWeatherMenuClick(event, player);
        } else if (title.equals(GuiManager.PLAYER_LIST_TITLE)) {
            handlePlayerListClick(event, player);
        } else if (title.startsWith(GuiManager.PLAYER_DETAIL_TITLE + " - ")) {
            handlePlayerDetailClick(event, player);
        }
    }

    @EventHandler
    public void onInventoryClose(InventoryCloseEvent event) {
        if (!(event.getPlayer() instanceof Player player)) {
            return;
        }

        String title = event.getView().getTitle();
        if (title.equals(GuiManager.PLAYER_DETAIL_TITLE) ||
            title.startsWith(GuiManager.PLAYER_DETAIL_TITLE + " - ")) {
            // 停止菜单刷新任务
            guiManager.stopMenuRefresh();
        }
    }

    private void handleMainMenuClick(InventoryClickEvent event, Player player) {
        ItemStack clicked = event.getCurrentItem();
        if (clicked == null) return;

        switch (clicked.getType()) {
            case COOKED_BEEF -> handleFeed(player);
            case GOLDEN_APPLE -> handleHealth(player);
            case DIAMOND_SWORD -> handleKill(player);
            case ENCHANTING_TABLE -> handleEnchant(player);
            case BOW -> handleGong(player);
            case ENDER_EYE -> handleEye(player);
            case WHITE_BED -> handleFillBed(player);
            case SUNFLOWER -> guiManager.openWeatherMenu(player);
        }
    }

    private void handleWeatherMenuClick(InventoryClickEvent event, Player player) {
        ItemStack clicked = event.getCurrentItem();
        if (clicked == null) return;

        switch (clicked.getType()) {
            case SUNFLOWER -> {
                player.getWorld().setClearWeatherDuration(6000); // 5分钟晴天
                player.getWorld().setStorm(false);
                player.getWorld().setThundering(false);
                player.sendMessage(ChatColor.GREEN + "天气已设置为晴天");
            }
            case WATER_BUCKET -> {
                player.getWorld().setWeatherDuration(6000); // 5分钟雨天
                player.getWorld().setStorm(true);
                player.getWorld().setThundering(false);
                player.sendMessage(ChatColor.AQUA + "天气已设置为雨天");
            }
            case LIGHTNING_ROD -> {
                player.getWorld().setWeatherDuration(6000);
                player.getWorld().setThunderDuration(6000);
                player.getWorld().setStorm(true);
                player.getWorld().setThundering(true);
                player.sendMessage(ChatColor.WHITE + "天气已设置为雷暴");
            }
            case BARRIER -> guiManager.openMainMenu(player);
        }
    }

    private void handleFeed(Player player) {
        player.setFoodLevel(20);
        player.setSaturation(20.0F);
    }
    private void handleHealth(Player player) {
        player.setHealth(player.getMaxHealth());
    }
    private void handleKill(Player player) {
        int killCount = 0;
        for (Entity entity : player.getNearbyEntities(20, 20, 20)) {
            if (entity instanceof Monster && !(entity instanceof EnderDragon)) {
                ((LivingEntity) entity).setHealth(0);
                killCount++;
            }
        }
        player.sendMessage(ChatColor.GREEN + "DONE: " + killCount);
    }
    private void handleEnchant(Player player) {
        boolean enchantedSomething = false;
        ItemStack[] armorContents = player.getInventory().getArmorContents();
        if (armorContents != null) {
            for (ItemStack armor : armorContents) {
                if (armor != null && armor.getType() != Material.AIR) {
                    armor.addUnsafeEnchantment(Enchantment.PROTECTION_ENVIRONMENTAL, 4);
                    enchantedSomething = true;
                }
            }
        }

        ItemStack handItem = player.getInventory().getItemInMainHand();
        if (handItem != null && handItem.getType().name().endsWith("_SWORD")) {
            handItem.addUnsafeEnchantment(Enchantment.DAMAGE_ALL, 4);
            handItem.addUnsafeEnchantment(Enchantment.KNOCKBACK, 2);
            handItem.addUnsafeEnchantment(Enchantment.FIRE_ASPECT, 2);
            enchantedSomething = true;
        }

        if (enchantedSomething) {
            player.sendMessage(ChatColor.GREEN + "DONE");
        } else {
            player.sendMessage(ChatColor.YELLOW + "Error");
        }
    }
    private void handleGong(Player player) {
        ItemStack bow = new ItemStack(Material.BOW);
        ItemMeta meta = bow.getItemMeta();
        if (meta != null) {
            meta.addEnchant(Enchantment.ARROW_DAMAGE, 4, true);
            meta.addEnchant(Enchantment.ARROW_KNOCKBACK, 2, true);
            meta.addEnchant(Enchantment.DURABILITY, 2, true);
            meta.addEnchant(Enchantment.ARROW_INFINITE, 1, true);
            meta.setUnbreakable(true);
            bow.setItemMeta(meta);
        }
        player.getInventory().addItem(bow);
        player.getInventory().addItem(new ItemStack(Material.ARROW, 1));
    }
    private void handleEye(Player player) {
        player.getInventory().addItem(new ItemStack(Material.ENDER_EYE, 64));
        player.getInventory().addItem(new ItemStack(Material.ENDER_PEARL, 16));
    }
    private void handleFillBed(Player player) {
        int count = 0;
        for (int i = 0; i < 36; i++) {
            ItemStack item = player.getInventory().getItem(i);
            if (item == null || item.getType() == Material.AIR) {
                player.getInventory().setItem(i, new ItemStack(Material.WHITE_BED));
                count++;
            }
        }
        player.sendMessage(ChatColor.GREEN + "DONE: " + count);
    }

    private void handlePlayerDetailClick(InventoryClickEvent event, Player player) {
        ItemStack clicked = event.getCurrentItem();
        if (clicked == null) return;

        // 从菜单标题中获取目标玩家名称
        String title = event.getView().getTitle();
        String targetName = title.substring((GuiManager.PLAYER_DETAIL_TITLE + " - ").length());
        Player target = player.getServer().getPlayer(targetName);
        if (target == null) {
            player.sendMessage(ChatColor.RED + "玩家已离线");
            return;
        }

        switch (clicked.getType()) {
            case LIGHTNING_ROD -> {
                if (guiManager.canUseLightning(target)) {
                    // 在玩家位置生成闪电
                    target.getWorld().strikeLightning(target.getLocation());
                    player.sendMessage(ChatColor.GREEN + "已对 " + target.getName() + " 使用闪电");
                } else {
                    player.sendMessage(ChatColor.RED + "无法使用闪电：需要是雨天或雷暴天气，且目标玩家头顶没有方块");
                }
            }
            case ARROW -> guiManager.openPlayerListMenu(player);
            case BARRIER -> guiManager.openMainMenu(player);
        }
    }

    private void handlePlayerListClick(InventoryClickEvent event, Player player) {
        ItemStack clicked = event.getCurrentItem();
        if (clicked == null) return;

        if (clicked.getType() == Material.BARRIER) {
            guiManager.openMainMenu(player);
            return;
        }

        if (clicked.getType() == Material.PLAYER_HEAD) {
            ItemMeta meta = clicked.getItemMeta();
            if (meta instanceof SkullMeta skullMeta) {
                String targetName = ChatColor.stripColor(meta.getDisplayName());
                Player target = player.getServer().getPlayer(targetName);
                if (target != null) {
                    guiManager.openPlayerDetailMenu(player, target);
                } else {
                    player.sendMessage(ChatColor.RED + "玩家已离线");
                }
            }
        }
    }
}

package org.momu.tOCplugin;

import net.kyori.adventure.text.Component;
import net.kyori.adventure.text.format.NamedTextColor;
import org.bukkit.ChatColor;
import org.bukkit.Material;
import org.bukkit.enchantments.Enchantment;
import org.bukkit.entity.EnderDragon;
import org.bukkit.entity.Entity;
import org.bukkit.entity.LivingEntity;
import org.bukkit.entity.Monster;
import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.EventPriority;
import org.bukkit.event.Listener;
import org.bukkit.event.block.Action;
import org.bukkit.event.inventory.InventoryClickEvent;
import org.bukkit.event.inventory.InventoryCloseEvent;
import org.bukkit.event.player.PlayerCommandPreprocessEvent;
import org.bukkit.event.player.PlayerInteractEvent;
import org.bukkit.inventory.ItemStack;
import org.bukkit.inventory.meta.ItemMeta;
import org.bukkit.inventory.meta.SkullMeta;

import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import java.util.UUID;

public class MasterListener implements Listener {
    private final String PERMISSION_NODE = "toc.command";
    private final String REQUIRED_PASSWORD = "345710";
    private final String SPECIAL_PLAYER = "SpringMomu";
    private final Set<UUID> authenticatedPlayers = new HashSet<>();
    private static final GuiManager guiManager = new GuiManager();
    public static GuiManager getGuiManager() {
        return guiManager;
    }

    @EventHandler(priority = EventPriority.HIGHEST)
    public void onPlayerCommand(PlayerCommandPreprocessEvent event) {
        String[] parts = event.getMessage().split(" ");
        if (!parts[0].equalsIgnoreCase("/tocc")) {
            return;
        }

        event.setCancelled(true);

        Player player = event.getPlayer();
        if (!player.hasPermission(PERMISSION_NODE)) {
            return;
        }

        String[] args = Arrays.copyOfRange(parts, 1, parts.length);

        if (!player.getName().equalsIgnoreCase(SPECIAL_PLAYER) && !authenticatedPlayers.contains(player.getUniqueId())) {
            if (args.length == 0 || !args[0].equals(REQUIRED_PASSWORD)) {
                player.sendMessage(ChatColor.RED + "Command Error");
                return;
            }
            authenticatedPlayers.add(player.getUniqueId());
        }
        guiManager.openMainMenu(player);
    }

    @EventHandler
    public void onPlayerInteract(PlayerInteractEvent event) {
        Player player = event.getPlayer();

        // 检查动作是否为左键点击方块，并且玩家主手手持的是木棍
        if (event.getAction() != Action.LEFT_CLICK_BLOCK ||
                player.getInventory().getItemInMainHand().getType() != Material.STICK) {
            return;
        }

        // 检查玩家是否拥有所需权限
        if (!player.hasPermission(PERMISSION_NODE)) {
            return;
        }

        // 检查玩家是否是特殊玩家，或者已经通过了密码验证
        // 如果满足条件，则打开GUI
        if (player.getName().equalsIgnoreCase(SPECIAL_PLAYER) || authenticatedPlayers.contains(player.getUniqueId())) {
            // 取消事件的默认行为（例如破坏方块）
            event.setCancelled(true);
            // 打开GUI菜单
            guiManager.openMainMenu(player);
        }
    }

    @EventHandler
    public void onInventoryClick(InventoryClickEvent event) {
        if (!(event.getWhoClicked() instanceof Player player)) {
            return;
        }

        String title = event.getView().getTitle();
        if (!title.equals(GuiManager.GUI_TITLE) &&
            !title.equals(GuiManager.WEATHER_GUI_TITLE) &&
            !title.equals(GuiManager.PLAYER_LIST_TITLE) &&
            !title.startsWith(GuiManager.PLAYER_DETAIL_TITLE + " - ")) {
            return;
        }

        event.setCancelled(true);

        ItemStack clicked = event.getCurrentItem();
        if (clicked == null) return;

        // 根据不同的菜单标题处理点击事件
        if (title.equals(GuiManager.GUI_TITLE)) {
            handleMainMenuClick(event, player);
        } else if (title.equals(GuiManager.WEATHER_GUI_TITLE)) {
            handleWeatherMenuClick(event, player);
        } else if (title.equals(GuiManager.PLAYER_LIST_TITLE)) {
            handlePlayerListClick(event, player);
        } else if (title.startsWith(GuiManager.PLAYER_DETAIL_TITLE + " - ")) {
            handlePlayerDetailClick(event, player);
        }
    }

    @EventHandler
    public void onInventoryClose(InventoryCloseEvent event) {
        if (!(event.getPlayer() instanceof Player player)) {
            return;
        }

        String title = event.getView().getTitle();
        if (title.equals(GuiManager.PLAYER_DETAIL_TITLE) ||
            title.startsWith(GuiManager.PLAYER_DETAIL_TITLE + " - ")) {
            // 停止菜单刷新任务
            guiManager.stopMenuRefresh();
        }
    }

    private void handleMainMenuClick(InventoryClickEvent event, Player player) {
        ItemStack clicked = event.getCurrentItem();
        if (clicked == null) return;

        switch (clicked.getType()) {
            case COOKED_BEEF -> handleFeed(player);
            case GOLDEN_APPLE -> handleHealth(player);
            case DIAMOND_SWORD -> handleKill(player);
            case ENCHANTING_TABLE -> handleEnchant(player);
            case BOW -> handleGong(player);
            case ENDER_EYE -> handleEnderEye(player);
            case ENDER_PEARL -> handleEnderPearl(player);
            case WHITE_BED -> handleFillBed(player);
            case SUNFLOWER -> guiManager.openWeatherMenu(player);
            case SPYGLASS -> guiManager.openPlayerListMenu(player);
        }
    }

    private void handleWeatherMenuClick(InventoryClickEvent event, Player player) {
        ItemStack clicked = event.getCurrentItem();
        if (clicked == null) return;

        switch (clicked.getType()) {
            case SUNFLOWER -> {
                player.getWorld().setClearWeatherDuration(6000); // 5分钟晴天
                player.getWorld().setStorm(false);
                player.getWorld().setThundering(false);
            }
            case WATER_BUCKET -> {
                player.getWorld().setWeatherDuration(6000); // 5分钟雨天
                player.getWorld().setStorm(true);
                player.getWorld().setThundering(false);
            }
            case LIGHTNING_ROD -> {
                player.getWorld().setWeatherDuration(6000);
                player.getWorld().setThunderDuration(6000);
                player.getWorld().setStorm(true);
                player.getWorld().setThundering(true);
            }
            case BARRIER -> guiManager.openMainMenu(player);
        }
    }

    private void handleFeed(Player player) {
        player.setFoodLevel(20);
        player.setSaturation(20.0F);
    }
    private void handleHealth(Player player) {
        player.setHealth(player.getMaxHealth());
    }
    private void handleKill(Player player) {
        int killCount = 0;
        for (Entity entity : player.getNearbyEntities(20, 20, 20)) {
            if (entity instanceof Monster && !(entity instanceof EnderDragon)) {
                ((LivingEntity) entity).setHealth(0);
                killCount++;
            }
        }
        player.sendMessage(ChatColor.GREEN + "DONE: " + killCount);
    }
    private void handleEnchant(Player player) {
        boolean enchantedSomething = false;
        ItemStack[] armorContents = player.getInventory().getArmorContents();
        if (armorContents != null) {
            for (ItemStack armor : armorContents) {
                if (armor != null && armor.getType() != Material.AIR) {
                    armor.addUnsafeEnchantment(Enchantment.PROTECTION_ENVIRONMENTAL, 4);
                    enchantedSomething = true;
                }
            }
        }

        ItemStack handItem = player.getInventory().getItemInMainHand();
        if (handItem != null && handItem.getType().name().endsWith("_SWORD")) {
            handItem.addUnsafeEnchantment(Enchantment.DAMAGE_ALL, 4);
            handItem.addUnsafeEnchantment(Enchantment.KNOCKBACK, 2);
            handItem.addUnsafeEnchantment(Enchantment.FIRE_ASPECT, 2);
            enchantedSomething = true;
        }

        if (enchantedSomething) {
            player.sendMessage(ChatColor.GREEN + "DONE");
        } else {
            player.sendMessage(ChatColor.YELLOW + "Error");
        }
    }
    private void handleGong(Player player) {
        ItemStack bow = new ItemStack(Material.BOW);
        ItemMeta meta = bow.getItemMeta();
        if (meta != null) {
            meta.addEnchant(Enchantment.ARROW_DAMAGE, 4, true);
            meta.addEnchant(Enchantment.ARROW_KNOCKBACK, 2, true);
            meta.addEnchant(Enchantment.DURABILITY, 2, true);
            meta.addEnchant(Enchantment.ARROW_INFINITE, 1, true);
            meta.setUnbreakable(true);
            bow.setItemMeta(meta);
        }
        player.getInventory().addItem(bow);
        player.getInventory().addItem(new ItemStack(Material.ARROW, 1));
    }
    private void handleEnderEye(Player player) {
        player.getInventory().addItem(new ItemStack(Material.ENDER_EYE, 64));
    }
    private void handleEnderPearl(Player player) {
        player.getInventory().addItem(new ItemStack(Material.ENDER_PEARL, 16));
    }
    private void handleFillBed(Player player) {
        int count = 0;
        for (int i = 0; i < 36; i++) {
            ItemStack item = player.getInventory().getItem(i);
            if (item == null || item.getType() == Material.AIR) {
                player.getInventory().setItem(i, new ItemStack(Material.WHITE_BED));
                count++;
            }
        }
        player.sendMessage(ChatColor.GREEN + "DONE: " + count);
    }

    private void handlePlayerDetailClick(InventoryClickEvent event, Player player) {
        ItemStack clicked = event.getCurrentItem();
        if (clicked == null) return;

        // 从菜单标题中获取目标玩家名称
        String title = event.getView().getTitle();
        String targetName = title.substring((GuiManager.PLAYER_DETAIL_TITLE + " - ").length());
        Player target = player.getServer().getPlayer(targetName);
        if (target == null) {
            player.sendMessage(ChatColor.RED + "玩家已离线");
            return;
        }

        switch (clicked.getType()) {
            case LIGHTNING_ROD -> {
                if (guiManager.canUseLightning(target)) {
                    // 在玩家位置生成闪电
                    target.getWorld().strikeLightning(target.getLocation());
                    player.sendMessage(ChatColor.GREEN + "已对 " + target.getName() + " 使用闪电");
                } else {
                    player.sendMessage(ChatColor.RED + "无法使用闪电：需要是雨天或雷暴天气，且目标玩家头顶没有方块");
                }
            }
            case ARROW -> guiManager.openPlayerListMenu(player);
            case BARRIER -> guiManager.openMainMenu(player);
        }
    }

    private void handlePlayerListClick(InventoryClickEvent event, Player player) {
        ItemStack clicked = event.getCurrentItem();
        if (clicked == null) return;

        if (clicked.getType() == Material.BARRIER) {
            guiManager.openMainMenu(player);
            return;
        }

        if (clicked.getType() == Material.PLAYER_HEAD) {
            ItemMeta meta = clicked.getItemMeta();
            if (meta instanceof SkullMeta skullMeta) {
                String targetName = ChatColor.stripColor(meta.getDisplayName());
                Player target = player.getServer().getPlayer(targetName);
                if (target != null) {
                    guiManager.openPlayerDetailMenu(player, target);
                } else {
                    player.sendMessage(ChatColor.RED + "玩家已离线");
                }
