}

package org.momu.tOCplugin;

import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.NamespacedKey;
import org.bukkit.Sound;
import org.bukkit.command.CommandExecutor;
import org.bukkit.command.TabCompleter;
import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.Listener;
import org.bukkit.event.player.PlayerJoinEvent;
import org.bukkit.plugin.java.JavaPlugin;
import org.bukkit.scheduler.BukkitTask;
import net.kyori.adventure.text.Component;
import net.kyori.adventure.title.Title;
import java.time.Duration;

import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;

import org.bukkit.configuration.file.FileConfiguration;
import org.bukkit.configuration.file.YamlConfiguration;

public final class TOCplugin
extends JavaPlugin
implements Listener {
    private BukkitTask guiUpdaterTask;

    public void onEnable() {
        // 保存默认配置文件，如果不存在的话
        this.saveDefaultConfig();

        // 更新配置文件，保留用户修改的值
        updateConfig();

        MainCommand mainCommand = new MainCommand(this);
        if (this.getCommand("toc") != null) {
            this.getCommand("toc").setExecutor(mainCommand);
            this.getCommand("toc").setTabCompleter(mainCommand);
        }

        this.getLogger().info("TOCplugin已启用。");
        this.getServer().getPluginManager().registerEvents(new MasterListener(), this);
        this.getServer().getPluginManager().registerEvents(this, this);
        this.getServer().getPluginManager().registerEvents(new PlayerMoveListener(this), this);
        this.guiUpdaterTask = Bukkit.getScheduler().runTaskTimer(this, MasterListener.getGuiManager()::updateOpenGuis, 0L, 20L);
    }

    public void onDisable() {
        this.getLogger().info("TOCplugin已禁用。");
        if (this.guiUpdaterTask != null) {
            this.guiUpdaterTask.cancel();
        }
    }

    @EventHandler
    public void onPlayerJoin(PlayerJoinEvent event) {
        String server = "当前服务器";
        Player player = event.getPlayer();

        // 使用新的Title API
        Title.Times times = Title.Times.times(
            Duration.ofMillis(500),  // fadeIn
            Duration.ofMillis(5000), // stay
            Duration.ofMillis(3000)  // fadeOut
        );

        Component mainTitle = Component.text(getServer().getName());
        Component subTitle = Component.text(server).color(net.kyori.adventure.text.format.NamedTextColor.AQUA);

        Title title = Title.title(mainTitle, subTitle, times);
        player.showTitle(title);

        player.playSound(player.getLocation(), Sound.ENTITY_PLAYER_LEVELUP, 1.0f, 1.2f);
    }

    public NamespacedKey getPlayerBiomeKey(Location location) {
        return location.getWorld().getBiome(location).getKey();
    }

    public String getTranslatedBiomeName(NamespacedKey key) {
        String keyString = key.toString();
        String translation = this.getConfig().getString("biome-translations." + keyString);
        if (translation != null && !translation.isEmpty()) {
            return translation;
        }
        String name = key.getKey().replace('_', ' ');
        String[] words = name.split(" ");
        StringBuilder capitalized = new StringBuilder();
        for (String word : words) {
            capitalized.append(Character.toUpperCase(word.charAt(0)))
                      .append(word.substring(1))
                      .append(" ");
        }
        return capitalized.toString().trim();
    }

    private void updateConfig() {
        // 获取默认配置文件中的所有键
        InputStream defaultConfigStream = getResource("config.yml");
        if (defaultConfigStream != null) {
            try {
                // 加载默认配置
                YamlConfiguration defaultConfig = YamlConfiguration.loadConfiguration(new InputStreamReader(defaultConfigStream));
                // 获取当前配置
                FileConfiguration currentConfig = getConfig();

                // 遍历默认配置中的所有键
                for (String key : defaultConfig.getKeys(true)) {
                    if (!currentConfig.contains(key)) {
                        // 如果当前配置中没有这个键，就添加它
                        currentConfig.set(key, defaultConfig.get(key));
                    }
                }

                // 保存更新后的配置
                saveConfig();
            } catch (Exception e) {
                getLogger().warning("更新配置文件时出现错误: " + e.getMessage());
            } finally {
                try {
                    defaultConfigStream.close();
                } catch (IOException e) {
                    getLogger().warning("关闭配置文件流时出现错误: " + e.getMessage());
                }
            }
        }
    }
}

